using System.Text.Json;
using System.Text.Json.Serialization;
using System.Text.Json.Serialization.Metadata;

// --- Options with the default reflection-based resolver ---
var options = new JsonSerializerOptions(JsonSerializerDefaults.Web);

// 1. GetTypeInfo<T>() – returns a strongly-typed JsonTypeInfo<T>
JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();
Console.WriteLine($"GetTypeInfo<Person> resolved type: {personInfo.Type.Name}");

string json = JsonSerializer.Serialize(new Person("Ada", 36), personInfo);
Console.WriteLine($"Serialized: {json}");

// 2. TryGetTypeInfo<T>() – probe without throwing
//    Person is resolvable (reflection resolver handles it):
if (options.TryGetTypeInfo<Person>(out JsonTypeInfo<Person>? found))
    Console.WriteLine($"TryGetTypeInfo<Person> succeeded: {found!.Type.Name}");
else
    Console.WriteLine("TryGetTypeInfo<Person> returned false");

// Now try a source-gen-only options instance that has NO resolver at all.
// TryGetTypeInfo returns false instead of throwing.
var limited = new JsonSerializerOptions { TypeInfoResolver = null };

if (limited.TryGetTypeInfo<Person>(out JsonTypeInfo<Person>? missing))
    Console.WriteLine($"TryGetTypeInfo<Person> on limited options succeeded: {missing!.Type.Name}");
else
    Console.WriteLine("TryGetTypeInfo<Person> on limited options: not available (no resolver)");

// --- Helper type ---
public record Person(string Name, int Age);

